import{_ as i,o as e,c as l,a2 as t}from"./chunks/framework.LN3EJxkW.js";const p=JSON.parse('{"title":"Mention 提及","description":"","frontmatter":{"title":"Mention 提及","stage":"intermediate","direction":"interaction-design","tags":["interaction-patterns","collaboration","mention"]},"headers":[],"relativePath":"03-interaction-design/notes/06-interaction-patterns/05-collaboration/mention.md","filePath":"03-interaction-design/notes/06-interaction-patterns/05-collaboration/mention.md","lastUpdated":1784542968000}'),o={name:"03-interaction-design/notes/06-interaction-patterns/05-collaboration/mention.md"};function n(r,a,d,h,s,c){return e(),l("div",null,[...a[0]||(a[0]=[t(`<h1 id="mention-提及" tabindex="-1">Mention 提及 <a class="header-anchor" href="#mention-提及" aria-label="Permalink to &quot;Mention 提及&quot;">​</a></h1><p>Mention 是内容中的结构化身份引用，可选择性触发收件箱或通知路由。显示出来的 <code>@名称</code> 只是表示层；可靠系统必须保存被提及主体的稳定身份、提及发生时的可见范围、通知决策和后续身份变化。</p><h2 id="能力边界与前置知识" tabindex="-1">能力边界与前置知识 <a class="header-anchor" href="#能力边界与前置知识" aria-label="Permalink to &quot;能力边界与前置知识&quot;">​</a></h2><p>本文聚焦：</p><ul><li>输入过程中怎样过滤、排序和选择候选人或团队。</li><li>怎样区分稳定身份、用户名、显示名和历史名称。</li><li>提及与通知、授权、任务分派之间的边界。</li><li>编辑、删除、重命名、停用和跨组织身份的行为。</li><li>候选目录、通知预览和分析数据的隐私保护。</li></ul><p>前置知识：</p><ul><li>能为用户、服务账号和团队分配稳定 ID。</li><li>理解读取内容的权限不应由通知授予。</li><li>能实现可访问的可编辑输入与候选弹层。</li></ul><p>提及不是访问授权。把某人写进评论，不应自动让其读取原本无权访问的文档；若产品希望同时邀请，必须作为独立、可确认的分享操作。</p><h2 id="提及的结构" tabindex="-1">提及的结构 <a class="header-anchor" href="#提及的结构" aria-label="Permalink to &quot;提及的结构&quot;">​</a></h2><p>一条提及至少包含：</p><table tabindex="0"><thead><tr><th>字段</th><th>含义</th><th>边界</th></tr></thead><tbody><tr><td><code>mention_id</code></td><td>该次提及稳定标识</td><td>用于去重和撤销通知</td></tr><tr><td><code>content_id</code></td><td>所属评论、文档或事件</td><td>必须先授权读取</td></tr><tr><td><code>subject_type</code></td><td>user、team、role、service</td><td>不同类型路由不同</td></tr><tr><td><code>subject_id</code></td><td>被引用主体稳定 ID</td><td>重命名后不变</td></tr><tr><td><code>display_snapshot</code></td><td>创建时显示文本</td><td>用于历史与离线呈现</td></tr><tr><td><code>range</code></td><td>在结构化正文中的节点或范围</td><td>不依赖重新正则解析</td></tr><tr><td><code>created_by</code></td><td>发起主体</td><td>用于授权与限流</td></tr><tr><td><code>created_at</code></td><td>服务端时间</td><td>通知排序</td></tr><tr><td><code>notify_policy</code></td><td>是否有通知意图</td><td>不是最终投递结果</td></tr><tr><td><code>visibility_scope</code></td><td>提及时内容范围</td><td>防止通知预览越权</td></tr></tbody></table><p>W3C Activity Vocabulary 将 <code>Mention</code> 定义为一种专门的 Link。规范还指出，系统不应被迫解析正文中的 <code>@username</code> 字符串来决定通知路由；结构化 audience、tag 或 mention 关系更可靠。</p><h2 id="身份与显示名称" tabindex="-1">身份与显示名称 <a class="header-anchor" href="#身份与显示名称" aria-label="Permalink to &quot;身份与显示名称&quot;">​</a></h2><h3 id="稳定身份" tabindex="-1">稳定身份 <a class="header-anchor" href="#稳定身份" aria-label="Permalink to &quot;稳定身份&quot;">​</a></h3><p><code>subject_id</code> 指向目录中的主体，不因以下变化而改变：</p><ul><li>用户修改显示名。</li><li>用户名大小写或格式变化。</li><li>婚姻、语言或品牌名称变化。</li><li>团队改名。</li><li>头像更换。</li><li>账号被停用后恢复。</li></ul><p>内容渲染时可以使用当前显示名，也可在审计场景显示创建时快照。两者作用不同：</p><table tabindex="0"><thead><tr><th>名称</th><th>用途</th><th>风险</th></tr></thead><tbody><tr><td>当前显示名</td><td>便于现在识别人</td><td>历史内容外观变化</td></tr><tr><td>创建时快照</td><td>保留当时语境</td><td>可能含已更正或应删除的个人信息</td></tr><tr><td>唯一用户名</td><td>辅助消歧</td><td>可能被回收或改变</td></tr><tr><td>组织与团队标签</td><td>区分同名主体</td><td>可能泄露组织关系</td></tr></tbody></table><p>目录应避免回收已使用的唯一标识。若公开 handle 可回收，历史 mention 必须仍绑定不可回收的内部主体 ID，不能自动指向新账户。</p><h3 id="同名消歧" tabindex="-1">同名消歧 <a class="header-anchor" href="#同名消歧" aria-label="Permalink to &quot;同名消歧&quot;">​</a></h3><p>候选中出现两个“王晨”时，展示完成选择所需的最小附加信息，例如团队、岗位或组织。不要默认暴露邮箱、手机号、员工编号。</p><p>选择后内容可显示短名，但聚焦或打开详情时提供安全的身份说明。</p><h3 id="停用与删除" tabindex="-1">停用与删除 <a class="header-anchor" href="#停用与删除" aria-label="Permalink to &quot;停用与删除&quot;">​</a></h3><p>账号停用后：</p><ul><li>历史提及保留身份关系与允许展示的快照。</li><li>不再成为普通候选。</li><li>不发送新通知。</li><li>深链进入主体资料遵守当前目录权限。</li><li>若因数据删除要求清除姓名，历史内容显示去标识化主体。</li></ul><p>团队删除后，历史提及不能重新绑定同名新团队。</p><h2 id="候选过滤" tabindex="-1">候选过滤 <a class="header-anchor" href="#候选过滤" aria-label="Permalink to &quot;候选过滤&quot;">​</a></h2><h3 id="先授权再检索" tabindex="-1">先授权再检索 <a class="header-anchor" href="#先授权再检索" aria-label="Permalink to &quot;先授权再检索&quot;">​</a></h3><p>候选集合不是完整用户目录。服务端按以下条件求交集：</p><p>[ Candidates = DirectoryScope \\cap MentionablePolicy \\cap ContentVisibility \\cap QueryMatch ]</p><ul><li><code>DirectoryScope</code>：当前主体可搜索的组织或协作空间。</li><li><code>MentionablePolicy</code>：允许被提及的主体类型与状态。</li><li><code>ContentVisibility</code>：提及后能合法读取内容的主体。</li><li><code>QueryMatch</code>：显示名、允许的用户名或别名匹配。</li></ul><p>若产品允许“提及并邀请”，候选必须明确分成已有访问者与可邀请者；选择可邀请者后进入分享确认，不能静默扩权。</p><h3 id="查询触发" tabindex="-1">查询触发 <a class="header-anchor" href="#查询触发" aria-label="Permalink to &quot;查询触发&quot;">​</a></h3><p><code>@</code> 后输入可打开候选，但要定义：</p><ul><li>最少字符数。</li><li>中文拼音、英文前缀和多语言搜索。</li><li>空查询是否显示最近协作者。</li><li>是否允许空格和标点结束提及。</li><li>输入法 composition 期间不提前提交。</li><li>粘贴 <code>@名称</code> 是否只保留文本，还是解析受控结构。</li></ul><p>空查询显示“所有员工”会泄露目录并增加载荷。更安全的默认集合是当前对象协作者、最近互动者和明确允许的团队。</p><h3 id="排序" tabindex="-1">排序 <a class="header-anchor" href="#排序" aria-label="Permalink to &quot;排序&quot;">​</a></h3><p>排序可以组合：</p><ul><li>当前内容参与者。</li><li>当前项目成员。</li><li>最近协作者。</li><li>精确名称匹配。</li><li>前缀与别名匹配。</li><li>团队或角色类型。</li></ul><p>不应使用敏感绩效、私聊频率或不可解释画像。排序规则改变要监测同名误选，而不只看首项点击。</p><h3 id="服务端搜索" tabindex="-1">服务端搜索 <a class="header-anchor" href="#服务端搜索" aria-label="Permalink to &quot;服务端搜索&quot;">​</a></h3><p>客户端缓存只保存当前范围的最小候选。查询使用防抖、取消和请求身份，旧响应不能覆盖新输入。返回值只包含渲染候选所需字段。</p><p>零结果要区分：</p><ul><li>没有匹配的可提及主体。</li><li>查询失败。</li><li>输入过短。</li><li>目录受限。</li></ul><h2 id="输入控件与结构化内容" tabindex="-1">输入控件与结构化内容 <a class="header-anchor" href="#输入控件与结构化内容" aria-label="Permalink to &quot;输入控件与结构化内容&quot;">​</a></h2><h3 id="候选弹层" tabindex="-1">候选弹层 <a class="header-anchor" href="#候选弹层" aria-label="Permalink to &quot;候选弹层&quot;">​</a></h3><p>Mention 输入通常表现为富文本编辑器中的可编辑 combobox：</p><ul><li>文本光标留在编辑器。</li><li>候选弹层具有列表或网格语义。</li><li>上下键移动活动候选。</li><li>Enter 接受候选。</li><li>Escape 关闭并保留已输入文本。</li><li>普通文本编辑键继续由浏览器和操作系统处理。</li></ul><p>WAI-ARIA APG 给出 combobox/listbox 的键盘与 <code>aria-activedescendant</code> 模式，但富文本编辑器需在真实浏览器和辅助技术中验证；仅添加角色不能自动获得行为。</p><h3 id="提及节点" tabindex="-1">提及节点 <a class="header-anchor" href="#提及节点" aria-label="Permalink to &quot;提及节点&quot;">​</a></h3><p>选择后插入不可分割或受控编辑的结构节点：</p><ul><li>保存 <code>subject_type</code> 与 <code>subject_id</code>。</li><li>显示当前或快照名称。</li><li>Backspace 在边界处可一次删除整个节点，或先选中再删除。</li><li>光标不能停在内部并破坏 ID。</li><li>复制到支持结构的编辑器时保留节点；复制到纯文本时降级为 <code>@显示名</code>。</li><li>从外部粘贴纯文本不自动变成可通知身份，除非用户重新确认候选。</li></ul><p>重新解析正文字符串会在重命名、同名和邮箱样式文本中产生错误。</p><h2 id="提及与通知是两个决定" tabindex="-1">提及与通知是两个决定 <a class="header-anchor" href="#提及与通知是两个决定" aria-label="Permalink to &quot;提及与通知是两个决定&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    M[&quot;保存结构化 Mention&quot;] --&gt; A{&quot;内容对主体可读？&quot;}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A -- &quot;否&quot; --&gt; N[&quot;不投递；可提示分享&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A -- &quot;是&quot; --&gt; P{&quot;通知策略允许？&quot;}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    P -- &quot;否&quot; --&gt; R[&quot;保留引用，不通知&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    P -- &quot;是&quot; --&gt; D[&quot;创建通知事件&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; C[&quot;站内 / 邮件 / 推送渠道&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; X[&quot;按偏好、限流与去重投递&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>Activity Vocabulary 也区分 mention 引用与 audience/通知路由：可以存在不触发通知的 mention。</p><h3 id="最终通知策略" tabindex="-1">最终通知策略 <a class="header-anchor" href="#最终通知策略" aria-label="Permalink to &quot;最终通知策略&quot;">​</a></h3><p>最终投递由多项决定：</p><ul><li>发起人是否有提及该主体或团队的能力。</li><li>被提及者能否读取内容。</li><li>被提及者的通知偏好、免打扰和渠道。</li><li>组织对敏感内容的邮件预览策略。</li><li>同一内容短时间内的去重。</li><li>团队 mention 的人数与限流。</li><li>内容是否仍存在、mention 是否已删除。</li></ul><p>界面可以说明“将通知 8 人”，但数量必须按当前可投递范围计算，且不能泄露隐藏团队成员。</p><h3 id="通知内容" tabindex="-1">通知内容 <a class="header-anchor" href="#通知内容" aria-label="Permalink to &quot;通知内容&quot;">​</a></h3><p>通知只包含被提及者有权查看的最小信息：</p><ul><li>发起人显示名。</li><li>内容类型与安全标题。</li><li>受控摘要。</li><li>指向规范内容和锚点的深链。</li></ul><p>邮件和推送可能出现在锁屏或第三方基础设施中。敏感空间可只写“你有一条新的提及”，登录后再授权读取正文。</p><h2 id="团队、角色和广播提及" tabindex="-1">团队、角色和广播提及 <a class="header-anchor" href="#团队、角色和广播提及" aria-label="Permalink to &quot;团队、角色和广播提及&quot;">​</a></h2><h3 id="团队" tabindex="-1">团队 <a class="header-anchor" href="#团队" aria-label="Permalink to &quot;团队&quot;">​</a></h3><p>团队 mention 保存团队 ID，而不是发布时展开为一串用户节点。投递时记录当时实际接收成员集合或投递事件，便于解释谁收到通知。</p><p>团队改名不改变历史身份。成员后来加入，不应因旧 mention 自动收到旧通知，除非产品明确提供“未读团队收件箱”语义。</p><h3 id="角色" tabindex="-1">角色 <a class="header-anchor" href="#角色" aria-label="Permalink to &quot;角色&quot;">​</a></h3><p><code>@值班人员</code> 可能在不同时间指向不同人。内容引用的是角色还是当时承担角色的人，必须明确：</p><ul><li>角色 mention：显示动态角色，投递给事件发生时的当班主体。</li><li>人员快照：将当班人员解析为具体用户 mention。</li></ul><p>审计场景通常同时记录角色 ID 和解析到的用户 ID。</p><h3 id="广播" tabindex="-1">广播 <a class="header-anchor" href="#广播" aria-label="Permalink to &quot;广播&quot;">​</a></h3><p><code>@所有人</code>、<code>@频道</code> 等可能产生大量通知。需要：</p><ul><li>限定发起角色。</li><li>提交前显示影响范围。</li><li>支持组织禁用。</li><li>频率限制和滥用检测。</li><li>不在候选首位诱导使用。</li><li>对大群体使用摘要或收件箱，避免每次邮件。</li></ul><h2 id="编辑、删除与通知生命周期" tabindex="-1">编辑、删除与通知生命周期 <a class="header-anchor" href="#编辑、删除与通知生命周期" aria-label="Permalink to &quot;编辑、删除与通知生命周期&quot;">​</a></h2><h3 id="编辑新增-mention" tabindex="-1">编辑新增 Mention <a class="header-anchor" href="#编辑新增-mention" aria-label="Permalink to &quot;编辑新增 Mention&quot;">​</a></h3><p>编辑内容新增主体时，可以创建新通知事件。使用 <code>mention_id</code> 去重，保存成功前不投递。</p><h3 id="编辑移除-mention" tabindex="-1">编辑移除 Mention <a class="header-anchor" href="#编辑移除-mention" aria-label="Permalink to &quot;编辑移除 Mention&quot;">​</a></h3><p>移除后不可能收回已读邮件，但可以：</p><ul><li>将站内通知标记为已撤销或隐藏。</li><li>防止未发送渠道继续投递。</li><li>深链进入时不再高亮该 mention。</li><li>保留必要审计事件。</li></ul><h3 id="改写显示文本" tabindex="-1">改写显示文本 <a class="header-anchor" href="#改写显示文本" aria-label="Permalink to &quot;改写显示文本&quot;">​</a></h3><p>结构节点显示名更新不应重新通知。只有主体 ID 新增或变化才产生通知候选。</p><h3 id="删除内容" tabindex="-1">删除内容 <a class="header-anchor" href="#删除内容" aria-label="Permalink to &quot;删除内容&quot;">​</a></h3><p>删除评论或文档后，通知深链应显示对象已删除或不可访问，不应回退到包含敏感摘要的通知详情。</p><h3 id="批量编辑" tabindex="-1">批量编辑 <a class="header-anchor" href="#批量编辑" aria-label="Permalink to &quot;批量编辑&quot;">​</a></h3><p>导入或自动化修改大量内容时，默认不应为历史 mention 批量发送新通知。通知需要明确的发布事件与策略。</p><h2 id="权限和隐私" tabindex="-1">权限和隐私 <a class="header-anchor" href="#权限和隐私" aria-label="Permalink to &quot;权限和隐私&quot;">​</a></h2><h3 id="候选目录" tabindex="-1">候选目录 <a class="header-anchor" href="#候选目录" aria-label="Permalink to &quot;候选目录&quot;">​</a></h3><ul><li>不把完整组织目录下载到浏览器。</li><li>搜索响应按当前主体、对象和组织范围过滤。</li><li>不暴露邮箱等非必要字段。</li><li>外部协作者只看到允许互动的内部主体。</li><li>失败与零结果文案不泄露某人是否在组织中。</li><li>查询日志最小化并设置保留期。</li></ul><h3 id="内容读取" tabindex="-1">内容读取 <a class="header-anchor" href="#内容读取" aria-label="Permalink to &quot;内容读取&quot;">​</a></h3><p>通知不会创建内容访问。打开深链时服务端重新授权；预览、搜索索引和缓存使用同一规则。</p><h3 id="阻止与安全" tabindex="-1">阻止与安全 <a class="header-anchor" href="#阻止与安全" aria-label="Permalink to &quot;阻止与安全&quot;">​</a></h3><p>社交产品中的被屏蔽关系、骚扰保护与未成年人安全可能覆盖普通项目成员关系。系统应在候选和投递两处执行，不能只隐藏通知。</p><h3 id="自动主体" tabindex="-1">自动主体 <a class="header-anchor" href="#自动主体" aria-label="Permalink to &quot;自动主体&quot;">​</a></h3><p>机器人、集成和服务账号应明确标识。mention 机器人可能触发命令，确定性授权与业务校验必须在服务端执行，不能把自然语言提及当成安全命令。</p><h2 id="案例一-代码审查中的同名工程师" tabindex="-1">案例一：代码审查中的同名工程师 <a class="header-anchor" href="#案例一-代码审查中的同名工程师" aria-label="Permalink to &quot;案例一：代码审查中的同名工程师&quot;">​</a></h2><h3 id="输入" tabindex="-1">输入 <a class="header-anchor" href="#输入" aria-label="Permalink to &quot;输入&quot;">​</a></h3><p>跨组织仓库有两名显示名为“Alex Chen”的成员：一名属于核心团队，一名是外部供应商。评论作者输入 <code>@alex</code>，希望请核心团队的数据库负责人检查迁移脚本。</p><h3 id="候选设计" tabindex="-1">候选设计 <a class="header-anchor" href="#候选设计" aria-label="Permalink to &quot;候选设计&quot;">​</a></h3><p>服务端只返回对当前私有仓库有读取权限、状态有效且允许被提及的主体。候选显示：</p><ul><li>Alex Chen — 数据平台 — <code>@alex-db</code></li><li>Alex Chen — 外部协作者 — <code>@alex-vendor</code></li></ul><p>不显示完整邮箱。精确用户名匹配优先，但当前文件的 code owner 和已有审阅者也提高排序。</p><p>选择后插入 <code>subject_id=user_483</code> 的节点。即使核心工程师后来将用户名改为 <code>@alex-data</code>，历史 mention 仍指向同一账户，渲染为新名或带历史快照。</p><h3 id="通知" tabindex="-1">通知 <a class="header-anchor" href="#通知" aria-label="Permalink to &quot;通知&quot;">​</a></h3><p>保存评论后创建通知事件。若该用户已订阅整个 Pull Request，mention 通知与订阅更新去重为一个收件箱条目，但保留“被直接提及”原因。</p><p>编辑评论只是修正文案，不重新通知；将 mention 改成供应商主体时，为新主体创建新事件并撤销尚未投递的旧事件。</p><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ul><li>两个同名主体不会仅靠显示名解析。</li><li>外部供应商失去仓库权限后从候选消失。</li><li>修改用户名后历史 mention 深链仍正确。</li><li>保存失败不发送通知。</li><li>同一 mention 在 POST 响应重试时不重复投递。</li><li>键盘完成搜索、消歧、选择和删除节点。</li></ul><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>如果正文只保存 <code>@alex-db</code> 字符串，用户名被回收后可能链接到新人，通知重放也会错投。稳定主体 ID 必须随内容保存，显示用户名只是快照。</p><h2 id="案例二-医疗会诊记录中的受限提及" tabindex="-1">案例二：医疗会诊记录中的受限提及 <a class="header-anchor" href="#案例二-医疗会诊记录中的受限提及" aria-label="Permalink to &quot;案例二：医疗会诊记录中的受限提及&quot;">​</a></h2><h3 id="输入-1" tabindex="-1">输入 <a class="header-anchor" href="#输入-1" aria-label="Permalink to &quot;输入&quot;">​</a></h3><p>会诊记录包含敏感健康信息。主治医生、当前会诊团队和患者授权的外部专家可见。医院目录中还有大量与该病例无关的员工。</p><h3 id="候选与范围" tabindex="-1">候选与范围 <a class="header-anchor" href="#候选与范围" aria-label="Permalink to &quot;候选与范围&quot;">​</a></h3><p>空查询只显示当前病例团队，不显示全院目录。输入至少两个字符后，服务端在“可参与该病例”的受控目录中搜索。需要邀请外部专家时，使用独立分享流程完成身份验证、合规确认和访问期限，再允许 mention。</p><p>候选只显示姓名、专业和机构；不显示私人联系方式。无法访问病例的员工不会出现在候选，界面也不说明其是否存在。</p><h3 id="通知-1" tabindex="-1">通知 <a class="header-anchor" href="#通知-1" aria-label="Permalink to &quot;通知&quot;">​</a></h3><p>站内通知写“你在一份会诊记录中被提及”，锁屏推送不包含患者姓名、诊断或正文。打开后重新检查病例访问期限和患者授权。</p><p>团队 mention 保存团队 ID 和当时实际投递的临床人员 ID。轮班结束后，新成员不会收到旧邮件，但可以在有权限的病例活动中查看历史。</p><h3 id="编辑与撤权" tabindex="-1">编辑与撤权 <a class="header-anchor" href="#编辑与撤权" aria-label="Permalink to &quot;编辑与撤权&quot;">​</a></h3><p>医生误提及错误专家后立即移除。未发送通知被取消；若已经投递，站内条目改为“提及已移除”，且正文深链不再可读。患者撤销外部专家授权时，内容、通知预览、搜索和附件访问同时失效。</p><h3 id="验证-1" tabindex="-1">验证 <a class="header-anchor" href="#验证-1" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ul><li>非病例成员搜索不到患者团队。</li><li>锁屏和邮件不包含敏感摘要。</li><li>访问到期后旧通知不能打开内容。</li><li>团队换班不会把旧 mention 投给新人。</li><li>删除 mention 后不会因内容重新索引再次触发。</li><li>查询日志不保存患者姓名或完整输入。</li></ul><h3 id="失败分支-1" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支-1" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>若系统允许先提及任意医院员工，再在点击时显示无权限，候选列表本身已经泄露目录，通知也可能泄露病例存在性。过滤必须发生在搜索和投递之前。</p><h2 id="案例三-值班角色的动态身份" tabindex="-1">案例三：值班角色的动态身份 <a class="header-anchor" href="#案例三-值班角色的动态身份" aria-label="Permalink to &quot;案例三：值班角色的动态身份&quot;">​</a></h2><h3 id="输入-2" tabindex="-1">输入 <a class="header-anchor" href="#输入-2" aria-label="Permalink to &quot;输入&quot;">​</a></h3><p>运维记录允许 <code>@数据库值班</code>。值班角色每 8 小时轮换，提交事件时由排班系统返回当前主值班和备份。</p><h3 id="建模" tabindex="-1">建模 <a class="header-anchor" href="#建模" aria-label="Permalink to &quot;建模&quot;">​</a></h3><p>内容保存角色 mention：</p><ul><li><code>subject_type=role</code></li><li><code>subject_id=oncall-database</code></li><li>显示快照“数据库值班”</li></ul><p>通知事件另存解析结果 <code>user_72</code> 和 <code>user_19</code>，以及排班版本。这样历史内容仍引用职责，审计能回答当时实际通知了谁。</p><h3 id="异常" tabindex="-1">异常 <a class="header-anchor" href="#异常" aria-label="Permalink to &quot;异常&quot;">​</a></h3><p>排班服务不可用时，不猜测上一次值班人。保存内容可以成功，但通知状态标为未路由，并触发受控恢复；界面明确“提及已保存，值班通知尚未确认”。</p><h3 id="验证-2" tabindex="-1">验证 <a class="header-anchor" href="#验证-2" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ul><li>切班边界前后使用服务端事件时间解析。</li><li>排班服务恢复后同一 mention 只路由一次。</li><li>角色改名不改变 ID。</li><li>旧值班人离职后审计仍保留允许的主体记录。</li></ul><h3 id="失败分支-2" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支-2" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>若渲染页面时才动态展开角色，历史页面会显示当前值班人，好像当时通知了他。展示职责与实际投递快照必须分开。</p><h2 id="无障碍与输入法" tabindex="-1">无障碍与输入法 <a class="header-anchor" href="#无障碍与输入法" aria-label="Permalink to &quot;无障碍与输入法&quot;">​</a></h2><ul><li>编辑器有明确名称，mention 候选弹层状态可程序化确定。</li><li>活动候选的姓名、类型和消歧信息组成完整可访问名称。</li><li>候选数量变化使用适度状态消息，不逐个朗读所有结果。</li><li><code>Escape</code> 关闭候选但不丢失草稿。</li><li>输入法组合期间不截断文本或触发 Enter 选择。</li><li>提及节点有可读文本，不能只显示头像或颜色。</li><li>删除节点的键盘行为可预测，并可撤销本地误删。</li><li>200% 文本缩放与窄屏下候选不遮挡光标和当前输入。</li></ul><h2 id="观测与调试" tabindex="-1">观测与调试 <a class="header-anchor" href="#观测与调试" aria-label="Permalink to &quot;观测与调试&quot;">​</a></h2><h3 id="观测" tabindex="-1">观测 <a class="header-anchor" href="#观测" aria-label="Permalink to &quot;观测&quot;">​</a></h3><ul><li>候选查询零结果、取消、延迟和错误。</li><li>同名候选的误选后删除或替换。</li><li>mention 保存到通知创建、投递和打开的转化。</li><li>团队广播影响人数与限流。</li><li>无内容权限而被阻止的投递。</li><li>重命名、停用和删除后的失效引用。</li><li>重复通知去重与错误重投。</li></ul><p>不要记录原始敏感查询。成功打开率也不能证明通知内容合适。</p><h3 id="调试顺序" tabindex="-1">调试顺序 <a class="header-anchor" href="#调试顺序" aria-label="Permalink to &quot;调试顺序&quot;">​</a></h3><ol><li>固定发起人、内容、组织和主体范围。</li><li>检查目录授权与候选字段。</li><li>检查结构节点是否保存稳定主体 ID。</li><li>检查内容读取权限和通知策略。</li><li>检查 mention ID、编辑差异和投递去重。</li><li>检查重命名、停用与撤权后的渲染。</li><li>复测输入法、键盘和辅助技术。</li></ol><h2 id="失败注入" tabindex="-1">失败注入 <a class="header-anchor" href="#失败注入" aria-label="Permalink to &quot;失败注入&quot;">​</a></h2><ol><li>候选搜索期间撤销内容权限。</li><li>两个主体同名且用户名相近。</li><li>选择后、保存前主体停用。</li><li>保存成功但通知队列延迟。</li><li>编辑新增、替换和移除 mention。</li><li>团队在投递期间增删成员。</li><li>用户名被修改或公开 handle 被回收。</li><li>邮件已发送后内容被删除。</li></ol><h2 id="综合练习-设计结构化-mention" tabindex="-1">综合练习：设计结构化 Mention <a class="header-anchor" href="#综合练习-设计结构化-mention" aria-label="Permalink to &quot;综合练习：设计结构化 Mention&quot;">​</a></h2><p>为支持用户、团队和动态角色的富文本评论系统交付：</p><ol><li>mention 节点、主体目录与通知事件模型。</li><li>候选集合的权限求交和排序规则。</li><li>combobox 键盘、输入法和复制粘贴契约。</li><li>编辑、删除、重命名、停用与团队变更规则。</li><li>个人、团队、广播和角色通知策略。</li><li>隐私字段、日志保留和深链授权。</li><li>乱序、撤权、同名和重复投递测试。</li></ol><p>验收标准：</p><ul><li>正文不靠解析 <code>@字符串</code> 决定主体和通知。</li><li>候选列表不会泄露不可见目录。</li><li>提及不会隐式授予内容权限。</li><li>重命名和 handle 回收不会改变历史主体。</li><li>编辑只通知真正新增的主体。</li><li>团队 mention 能回答当时实际投递给谁。</li><li>键盘与输入法可完成全部选择和取消流程。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.w3.org/TR/activitystreams-vocabulary/#dfn-mention" target="_blank" rel="noreferrer">W3C：Activity Vocabulary — Mention</a>（访问日期：2026-07-18）</li><li><a href="https://www.w3.org/TR/activitystreams-core/" target="_blank" rel="noreferrer">W3C：Activity Streams 2.0</a>（访问日期：2026-07-18）</li><li><a href="https://www.w3.org/WAI/ARIA/apg/patterns/combobox/" target="_blank" rel="noreferrer">W3C WAI：ARIA Authoring Practices — Combobox Pattern</a>（访问日期：2026-07-18）</li><li><a href="https://docs.github.com/en/organizations/organizing-members-into-teams/about-teams" target="_blank" rel="noreferrer">GitHub Docs：About Organization Teams</a>（访问日期：2026-07-18）</li><li><a href="https://www.w3.org/WAI/WCAG22/Understanding/status-messages.html" target="_blank" rel="noreferrer">W3C WAI：Understanding SC 4.1.3 Status Messages</a>（访问日期：2026-07-18）</li></ul>`,156)])])}const b=i(o,[["render",n]]);export{p as __pageData,b as default};
